function ProjectCard() {
  return (
    <div
      style={{
        width: "100%",
        height: "698px",
        position: "relative",
        background: "white",
        overflow: "hidden",
        borderRadius: "12.934px",
      }}
    >
      {/* Line */}
      <div
        style={{
          position: "absolute",
          top: "71.14px",
          left: "49.15px",
          width: "1144px",
          height: "1px",
          background: "black",
        }}
      />
      {/* Year */}
      <div
        style={{
          position: "absolute",
          left: "47.86px",
          top: "34.27px",
          color: "black",
          fontSize: "20.694px",
          fontFamily: "Inter, sans-serif",
          fontWeight: "400",
        }}
      >
        2024 - 2025
      </div>
      {/* Project Title */}
      <div
        style={{
          position: "absolute",
          left: "44.62px",
          top: "82.78px",
          color: "black",
          fontSize: "62.083px",
          fontFamily: "Inter, sans-serif",
          fontWeight: "400",
        }}
      >
        Project Title
      </div>
      {/* Category */}
      <div
        style={{
          position: "absolute",
          left: "1007.55px",
          top: "34.27px",
          color: "black",
          fontSize: "20.694px",
          fontFamily: "Inter, sans-serif",
          fontWeight: "400",
        }}
      >
        Branding + Identity
      </div>
      {/* Arrow */}
      <div
        style={{
          position: "absolute",
          left: "1126.54px",
          top: "96.36px",
          width: "66.609px",
          height: "47.855px",
        }}
      >
        <svg
          width="66.609px"
          height="47.855px"
          viewBox="0 0 67 48"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
        >
          <path
            d="M10 24H57M57 24L42 9M57 24L42 39"
            stroke="black"
            strokeWidth="4"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      </div>
      {/* Image placeholder */}
      <div
        style={{
          position: "absolute",
          left: "49.15px",
          top: "169.43px",
          width: "1144px",
          height: "472.086px",
          background: "#D9D9D9",
        }}
      />
    </div>
  );
}

export default ProjectCard;
